mapper.select:
SELECT s.settlement_id, s.workshop_id, s.monthly, s.origin_commission, s.adjust_amount, s.final_amount, s.status, s.bill_date, s.paid_date, s.admin_checker_id, w.name AS workshopName, w.owner_id AS ownerId, u.name AS ownerName, au.name AS adminName FROM settlement s JOIN workshop w USING (workshop_id) JOIN user u ON w.owner_id = u.user_id LEFT JOIN user au ON s.admin_checker_id = au.user_id
1=1
AND s.status = #{status}
GROUP BY s.settlement_id ORDER BY s.bill_date DESC;

mapper.update:
UPDATE settlement SET status = #{status}, admin_checker_id = #{adminCheckerId}
, adjust_amount = -origin_commission , paid_date = NOW()
, paid_date = NOW()
WHERE settlement_id = #{settlementId}
